interface Point {
  readonly x: number;
  readonly y: number;
}

function distance(a: Point, b: Point): number {
  return Math.sqrt((b.x - a.x) ** 2 + (b.y - a.y) ** 2);
}

class MutablePoint implements Point {
  x: number; // satisfies interface — runtime mutability is an impl detail
  y: number;
  constructor(x: number, y: number) { this.x = x; this.y = y; }
}

const p1: Point = { x: 0, y: 0 };
// p1.x = 1; // Error: readonly via Point interface

const p2 = new MutablePoint(3, 4);
// Through Point lens — readonly
const through: Point = p2;
// through.x = 1; // Error
// Directly — not readonly (MutablePoint doesn't declare readonly)
p2.x = 1; // OK

@Injectable({ providedIn: 'root' })
export class ThemeService {
  private readonly _theme = signal<'light' | 'dark'>('light');

  // Public readonly signal — consumers read but cannot .set()
  readonly theme = this._theme.asReadonly();
  readonly isDark = computed(() => this._theme() === 'dark');

  toggle(): void {
    this._theme.update(t => t === 'light' ? 'dark' : 'light');
  }
}

